import React, { useState, useEffect } from 'react';
import { 
  AppBar, 
  Toolbar, 
  Typography, 
  IconButton, 
  useTheme, 
  alpha, 
  Box,
  Avatar,
  Menu,
  MenuItem,
  Switch,
  FormControlLabel,
  Button,
  Badge,
  Tooltip,
  useMediaQuery,
  Container
} from '@mui/material';
import { styled } from '@mui/material/styles';
import { 
  Notifications, 
  DirectionsCar, 
  DarkMode, 
  LightMode, 
  Menu as MenuIcon,
  KeyboardArrowDown,
  AccountCircle,
  Login,
  Logout,
  Settings,
  ConfirmationNumber
} from '@mui/icons-material';
import { motion, AnimatePresence } from 'framer-motion';
import { useThemeContext } from '../../context/ThemeContext';
import { useNavigate, Link as RouterLink } from 'react-router-dom';

// Объявляем типы для Telegram WebApp
declare global {
  interface Window {
    Telegram?: {
      WebApp?: {
        BackButton?: {
          isVisible: boolean;
          show: () => void;
          hide: () => void;
          onClick: (callback: () => void) => void;
        }
        MainButton?: {
          text: string;
          color: string;
          textColor: string;
          isVisible: boolean;
          isActive: boolean;
          show: () => void;
          hide: () => void;
          enable: () => void;
          disable: () => void;
          onClick: (callback: () => void) => void;
        }
        setHeaderColor: (color: string) => void;
        ready: () => void;
        expand: () => void;
      };
    };
  }
}

const StyledAppBar = styled(AppBar)(({ theme }) => ({
  boxShadow: 'none',
  background: 'transparent',
  position: 'sticky',
  top: 0,
  zIndex: theme.zIndex.drawer + 1,
  backdropFilter: 'blur(10px)',
  borderBottom: `1px solid ${alpha(theme.palette.divider, 0.1)}`,
}));

const AppBarInner = styled(Box)(({ theme }) => ({
  background: theme.palette.mode === 'light' 
    ? alpha(theme.palette.background.paper, 0.9)
    : alpha(theme.palette.background.paper, 0.9),
  boxShadow: theme.palette.mode === 'light'
    ? '0 4px 20px rgba(0, 0, 0, 0.05)'
    : '0 4px 20px rgba(0, 0, 0, 0.15)',
  borderRadius: '0 0 24px 24px',
  marginLeft: theme.spacing(1.5),
  marginRight: theme.spacing(1.5),
  padding: theme.spacing(0, 1),
  height: 64,
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'space-between',
  [theme.breakpoints.down('sm')]: {
    marginLeft: theme.spacing(1),
    marginRight: theme.spacing(1),
    borderRadius: '0 0 16px 16px',
    height: 56,
  },
}));

const LogoContainer = styled(Box)(({ theme }) => ({
  display: 'flex',
  alignItems: 'center',
}));

const IconContainer = styled(Box)(({ theme }) => ({
  display: 'flex',
  alignItems: 'center',
  gap: theme.spacing(1),
}));

const StyledIconButton = styled(IconButton)(({ theme }) => ({
  color: theme.palette.text.primary,
  backgroundColor: alpha(theme.palette.divider, 0.1),
  borderRadius: 12,
  padding: theme.spacing(1),
  '&:hover': {
    backgroundColor: alpha(theme.palette.divider, 0.2),
  },
  margin: theme.spacing(0, 0.5),
  transition: 'all 0.2s ease',
}));

const MaterialUISwitch = styled(Switch)(({ theme }) => ({
  width: 62,
  height: 34,
  padding: 7,
  '& .MuiSwitch-switchBase': {
    margin: 1,
    padding: 0,
    transform: 'translateX(6px)',
    '&.Mui-checked': {
      color: '#fff',
      transform: 'translateX(22px)',
      '& .MuiSwitch-thumb:before': {
        backgroundImage: `url('data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" height="20" width="20" viewBox="0 0 20 20"><path fill="${encodeURIComponent(
          '#fff',
        )}" d="M4.2 2.5l-.7 1.8-1.8.7 1.8.7.7 1.8.6-1.8L6.7 5l-1.9-.7-.6-1.8zm15 8.3a6.7 6.7 0 11-6.6-6.6 5.8 5.8 0 006.6 6.6z"/></svg>')`,
      },
      '& + .MuiSwitch-track': {
        opacity: 1,
        backgroundColor: theme.palette.mode === 'dark' ? '#8796A5' : '#aab4be',
      },
    },
  },
  '& .MuiSwitch-thumb': {
    backgroundColor: theme.palette.mode === 'dark' ? '#003892' : '#001e3c',
    width: 32,
    height: 32,
    '&:before': {
      content: "''",
      position: 'absolute',
      width: '100%',
      height: '100%',
      left: 0,
      top: 0,
      backgroundRepeat: 'no-repeat',
      backgroundPosition: 'center',
      backgroundImage: `url('data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" height="20" width="20" viewBox="0 0 20 20"><path fill="${encodeURIComponent(
        '#fff',
      )}" d="M9.305 1.667V3.75h1.389V1.667h-1.39zm-4.707 1.95l-.982.982L5.09 6.072l.982-.982-1.473-1.473zm10.802 0L13.927 5.09l.982.982 1.473-1.473-.982-.982zM10 5.139a4.872 4.872 0 00-4.862 4.86A4.872 4.872 0 0010 14.862 4.872 4.872 0 0014.86 10 4.872 4.872 0 0010 5.139zm0 1.389A3.462 3.462 0 0113.471 10a3.462 3.462 0 01-3.473 3.472A3.462 3.462 0 016.527 10 3.462 3.462 0 0110 6.528zM1.665 9.305v1.39h2.083v-1.39H1.666zm14.583 0v1.39h2.084v-1.39h-2.084zM5.09 13.928L3.616 15.4l.982.982 1.473-1.473-.982-.982zm9.82 0l-.982.982 1.473 1.473.982-.982-1.473-1.473zM9.305 16.25v2.083h1.389V16.25h-1.39z"/></svg>')`,
    },
  },
  '& .MuiSwitch-track': {
    opacity: 1,
    backgroundColor: theme.palette.mode === 'dark' ? '#8796A5' : '#aab4be',
    borderRadius: 20 / 2,
  },
}));

const LogoIcon = styled(DirectionsCar)(({ theme }) => ({
  fontSize: 28,
  color: theme.palette.primary.main,
  marginRight: theme.spacing(1),
}));

const NavButton = styled(Button)(({ theme }) => ({
  fontWeight: 600,
  borderRadius: 12,
  padding: theme.spacing(0.5, 2),
  textTransform: 'none',
  '&:hover': {
    backgroundColor: alpha(theme.palette.primary.main, 0.08),
  }
}));

const AppHeader: React.FC = () => {
  const theme = useTheme();
  const { mode, toggleTheme } = useThemeContext();
  const navigate = useNavigate();
  const isMobile = useMediaQuery(theme.breakpoints.down('sm'));
  const isTablet = useMediaQuery(theme.breakpoints.down('md'));
  
  const [anchorEl, setAnchorEl] = useState<null | HTMLElement>(null);
  const [mobileMenuAnchorEl, setMobileMenuAnchorEl] = useState<null | HTMLElement>(null);
  const [isTelegramMiniApp, setIsTelegramMiniApp] = useState(false);
  const [isAuthenticated, setIsAuthenticated] = useState(false); // Для примера

  const open = Boolean(anchorEl);
  const mobileMenuOpen = Boolean(mobileMenuAnchorEl);

  useEffect(() => {
    // Проверка на Telegram Mini App
    try {
      const isTelegram = Boolean(window?.Telegram?.WebApp);
      setIsTelegramMiniApp(isTelegram);
      
      // Настройка Telegram Mini App
      if (isTelegram && window.Telegram && window.Telegram.WebApp) {
        window.Telegram.WebApp.ready();
        // Установка цвета заголовка
        if (mode === 'dark') {
          window.Telegram.WebApp.setHeaderColor('#1e1e1e');
        } else {
          window.Telegram.WebApp.setHeaderColor('#ffffff');
        }
      }
    } catch (e) {
      setIsTelegramMiniApp(false);
    }
  }, [mode]);

  const handleProfileClick = (event: React.MouseEvent<HTMLElement>) => {
    setAnchorEl(event.currentTarget);
  };

  const handleMobileMenuOpen = (event: React.MouseEvent<HTMLElement>) => {
    setMobileMenuAnchorEl(event.currentTarget);
  };

  const handleClose = () => {
    setAnchorEl(null);
  };

  const handleMobileMenuClose = () => {
    setMobileMenuAnchorEl(null);
  };

  const handleLogin = () => {
    setIsAuthenticated(true);
    handleClose();
    handleMobileMenuClose();
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    handleClose();
    handleMobileMenuClose();
  };

  return (
    <StyledAppBar elevation={0} className="safe-area-padding">
      <Container maxWidth="lg" disableGutters>
        <AppBarInner>
          <LogoContainer>
            <motion.div
              initial={{ rotate: 0 }}
              animate={{ rotate: [0, -10, 10, 0] }}
              transition={{
                repeat: Infinity,
                repeatType: 'loop',
                duration: 5,
                ease: "easeInOut",
                times: [0, 0.2, 0.8, 1]
              }}
            >
              <LogoIcon />
            </motion.div>
            <Typography
              variant="h6"
              component={motion.h1}
              initial={{ opacity: 0, y: -5 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5 }}
              sx={{ 
                fontWeight: 800, 
                display: 'flex',
                alignItems: 'center',
                background: theme.palette.mode === 'dark'
                  ? 'linear-gradient(90deg, #64B5F6 0%, #2196F3 100%)'
                  : 'linear-gradient(90deg, #1976D2 0%, #2196F3 100%)',
                WebkitBackgroundClip: 'text',
                WebkitTextFillColor: 'transparent',
                mr: 1,
                fontSize: { xs: '1.1rem', sm: '1.3rem' }
              }}
            >
              АвтоШанс
            </Typography>
            
            {!isMobile && !isTelegramMiniApp && (
              <Box sx={{ display: 'flex', ml: 2 }}>
                <NavButton color="inherit" onClick={() => navigate('/')}>
                  Главная
                </NavButton>
                <NavButton color="inherit" onClick={() => navigate('/raffles')}>
                  Розыгрыши
                </NavButton>
                <NavButton color="inherit" onClick={() => navigate('/rewards')}>
                  Награды
                </NavButton>
              </Box>
            )}
          </LogoContainer>

          <IconContainer>
            {!isTelegramMiniApp && (
              <Tooltip title={mode === 'dark' ? 'Светлая тема' : 'Темная тема'}>
                <StyledIconButton onClick={toggleTheme} size="small">
                  {mode === 'dark' ? <LightMode /> : <DarkMode />}
                </StyledIconButton>
              </Tooltip>
            )}
            
            {!isMobile && !isTelegramMiniApp && (
              <Tooltip title="Уведомления">
                <StyledIconButton aria-label="notifications" size="small">
                  <Badge badgeContent={3} color="error">
                    <Notifications />
                  </Badge>
                </StyledIconButton>
              </Tooltip>
            )}
            
            {isAuthenticated ? (
              <Tooltip title="Профиль">
                <StyledIconButton 
                  aria-label="profile menu"
                  size="small" 
                  onClick={handleProfileClick}
                  aria-controls={open ? 'profile-menu' : undefined}
                  aria-haspopup="true"
                  aria-expanded={open ? 'true' : undefined}
                  sx={{ 
                    borderRadius: '12px', 
                    overflow: 'hidden',
                    background: alpha(theme.palette.primary.main, 0.1),
                    '&:hover': {
                      background: alpha(theme.palette.primary.main, 0.15),
                    }
                  }}
                >
                  <Avatar 
                    sx={{ 
                      width: 30, 
                      height: 30,
                      border: `2px solid ${alpha(theme.palette.primary.main, 0.3)}`
                    }}
                    alt="Профиль" 
                    src="/avatar-placeholder.jpg" 
                  />
                </StyledIconButton>
              </Tooltip>
            ) : (
              <Button
                variant="contained"
                color="primary"
                startIcon={<Login />}
                onClick={handleLogin}
                size={isMobile ? "small" : "medium"}
                sx={{ 
                  borderRadius: 12,
                  textTransform: 'none',
                  fontWeight: 600,
                  boxShadow: theme.shadows[4],
                  px: isMobile ? 1.5 : 2
                }}
              >
                {isMobile ? "Войти" : "Войти в аккаунт"}
              </Button>
            )}
            
            {isMobile && !isTelegramMiniApp && (
              <StyledIconButton
                edge="end"
                onClick={handleMobileMenuOpen}
                aria-label="меню"
                aria-controls={mobileMenuOpen ? 'mobile-menu' : undefined}
                aria-haspopup="true"
                aria-expanded={mobileMenuOpen ? 'true' : undefined}
              >
                <MenuIcon />
              </StyledIconButton>
            )}
          </IconContainer>
        </AppBarInner>
      </Container>
      
      {/* Выпадающее меню профиля */}
      <Menu
        id="profile-menu"
        anchorEl={anchorEl}
        open={open}
        onClose={handleClose}
        MenuListProps={{
          'aria-labelledby': 'profile-button',
        }}
        transformOrigin={{ horizontal: 'right', vertical: 'top' }}
        anchorOrigin={{ horizontal: 'right', vertical: 'bottom' }}
        PaperProps={{
          elevation: 3,
          sx: {
            mt: 1.5,
            overflow: 'visible',
            borderRadius: 3,
            minWidth: 180,
            boxShadow: theme.shadows[8],
            '&:before': {
              content: '""',
              display: 'block',
              position: 'absolute',
              top: 0,
              right: 14,
              width: 10,
              height: 10,
              bgcolor: 'background.paper',
              transform: 'translateY(-50%) rotate(45deg)',
              zIndex: 0,
            },
          },
        }}
      >
        <MenuItem onClick={() => {handleClose(); navigate('/profile')}} sx={{ borderRadius: 1 }}>
          <AccountCircle sx={{ mr: 1.5, fontSize: 20, color: 'text.secondary' }} />
          Профиль
        </MenuItem>
        <MenuItem onClick={() => {handleClose(); navigate('/tickets')}} sx={{ borderRadius: 1 }}>
          <ConfirmationNumber sx={{ mr: 1.5, fontSize: 20, color: 'text.secondary' }} />
          Мои билеты
        </MenuItem>
        <MenuItem onClick={() => {handleClose(); navigate('/settings')}} sx={{ borderRadius: 1 }}>
          <Settings sx={{ mr: 1.5, fontSize: 20, color: 'text.secondary' }} />
          Настройки
        </MenuItem>
        <MenuItem onClick={handleLogout} sx={{ borderRadius: 1, color: theme.palette.error.main }}>
          <Logout sx={{ mr: 1.5, fontSize: 20, color: theme.palette.error.main }} />
          Выйти
        </MenuItem>
      </Menu>
      
      {/* Мобильное меню */}
      <Menu
        id="mobile-menu"
        anchorEl={mobileMenuAnchorEl}
        open={mobileMenuOpen}
        onClose={handleMobileMenuClose}
        MenuListProps={{
          'aria-labelledby': 'mobile-menu-button',
        }}
        transformOrigin={{ horizontal: 'right', vertical: 'top' }}
        anchorOrigin={{ horizontal: 'right', vertical: 'bottom' }}
        PaperProps={{
          elevation: 3,
          sx: {
            mt: 1.5,
            overflow: 'visible',
            borderRadius: 3,
            minWidth: 200,
            boxShadow: theme.shadows[8],
            '&:before': {
              content: '""',
              display: 'block',
              position: 'absolute',
              top: 0,
              right: 14,
              width: 10,
              height: 10,
              bgcolor: 'background.paper',
              transform: 'translateY(-50%) rotate(45deg)',
              zIndex: 0,
            },
          },
        }}
      >
        <MenuItem onClick={() => {handleMobileMenuClose(); navigate('/')}} sx={{ borderRadius: 1 }}>
          Главная
        </MenuItem>
        <MenuItem onClick={() => {handleMobileMenuClose(); navigate('/raffles')}} sx={{ borderRadius: 1 }}>
          Розыгрыши
        </MenuItem>
        <MenuItem onClick={() => {handleMobileMenuClose(); navigate('/rewards')}} sx={{ borderRadius: 1 }}>
          Награды
        </MenuItem>
        <MenuItem onClick={() => {handleMobileMenuClose(); navigate('/notifications')}} sx={{ borderRadius: 1 }}>
          <Badge badgeContent={3} color="error" sx={{ '& .MuiBadge-badge': { right: -3, top: 3 } }}>
            <Box sx={{ mr: 1 }}>Уведомления</Box>
          </Badge>
        </MenuItem>
      </Menu>
    </StyledAppBar>
  );
};

export default AppHeader;
